import os
import io
import uuid
import pandas as pd
from PIL import Image
from flask import Flask, request, jsonify, send_from_directory
from collections import Counter
from sklearn.model_selection import train_test_split
from sklearn.svm import SVC # Example model
from sklearn.metrics import accuracy_score
import joblib # For saving/loading models
import numpy as np

# --- Configuration ---
UPLOAD_FOLDER = 'uploads'
LABELS_FILE = 'labels.csv'
MODEL_FILE = 'trained_model.joblib'
MIN_ANNOTATORS_FOR_AGGREGATION = 3 # Minimum annotations required for an image to be aggregated
MAJORITY_THRESHOLD = 0.5 # Proportion of annotators needed for a majority

app = Flask(__name__)
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

# --- Data Storage (In-memory, for simplicity. In production, use a database) ---
# Stores information about original images uploaded
images_info = {} # {image_id: {'filename': str, 'original_path': str, 'aggregated_label': str/None, 'status': 'pending'/'labeled'}}

# Stores raw annotations from annotators
# {image_id: [{'annotator_id': str, 'label': str, 'timestamp': str}, ...]}
raw_annotations = {}

# --- Helper Functions ---

def load_labels_df():
    """Loads aggregated labels from CSV or returns an empty DataFrame."""
    if os.path.exists(LABELS_FILE):
        return pd.read_csv(LABELS_FILE)
    return pd.DataFrame(columns=['image_id', 'aggregated_label', 'status', 'timestamp'])

def save_labels_df(df):
    """Saves the aggregated labels DataFrame to CSV."""
    df.to_csv(LABELS_FILE, index=False)

def aggregate_labels(image_id):
    """
    Aggregates labels for a given image_id using majority voting.
    Returns the majority label if criteria are met, otherwise None.
    """
    if image_id not in raw_annotations:
        return None

    annotations = raw_annotations[image_id]
    if len(annotations) < MIN_ANNOTATORS_FOR_AGGREGATION:
        return None

    labels = [ann['label'] for ann in annotations]
    label_counts = Counter(labels)

    # Find the label with the maximum count
    max_count_label, max_count = label_counts.most_common(1)[0]

    # Check if this label constitutes a majority
    if max_count / len(labels) >= MAJORITY_THRESHOLD:
        return max_count_label
    return None

def update_image_status(image_id, status, aggregated_label=None):
    """Updates the status and aggregated label of an image in images_info and labels.csv."""
    if image_id in images_info:
        images_info[image_id]['status'] = status
        if aggregated_label:
            images_info[image_id]['aggregated_label'] = aggregated_label

        labels_df = load_labels_df()
        if image_id in labels_df['image_id'].values:
            labels_df.loc[labels_df['image_id'] == image_id, 'status'] = status
            labels_df.loc[labels_df['image_id'] == image_id, 'aggregated_label'] = aggregated_label
        else:
            new_row = pd.DataFrame([{
                'image_id': image_id,
                'aggregated_label': aggregated_label,
                'status': status,
                'timestamp': pd.Timestamp.now().isoformat()
            }])
            labels_df = pd.concat([labels_df, new_row], ignore_index=True)
        save_labels_df(labels_df)

def load_image_as_features(image_path):
    """
    Example function to convert an image to a feature vector.
    THIS IS A SIMPLIFIED PLACEHOLDER. For a real ML system,
    you would use a proper image feature extraction method
    (e.g., pre-trained CNN features, resize + flatten, etc.).
    Here, it just flattens a resized grayscale image.
    """
    try:
        img = Image.open(image_path).convert('L') # Convert to grayscale
        img = img.resize((32, 32)) # Resize to a fixed size
        features = np.array(img).flatten() # Flatten the image into a 1D array
        return features
    except Exception as e:
        print(f"Error processing image {image_path}: {e}")
        return None

def train_model():
    """Trains a machine learning model on all available aggregated labeled data."""
    labels_df = load_labels_df()
    labeled_data = labels_df[labels_df['status'] == 'labeled']

    if labeled_data.empty:
        print("No labeled data available for training.")
        return False

    X_list = []
    y_list = []

    for _, row in labeled_data.iterrows():
        image_id = row['image_id']
        label = row['aggregated_label']
        if image_id in images_info:
            image_path = images_info[image_id]['original_path']
            features = load_image_as_features(image_path)
            if features is not None:
                X_list.append(features)
                y_list.append(label)
        else:
            print(f"Warning: Image info for {image_id} not found in in-memory store.")

    if not X_list:
        print("No features extracted for training.")
        return False

    X = np.array(X_list)
    y = np.array(y_list)

    # In a real scenario, you'd perform validation, but the requirement is "without validation"
    # So, we train on all available labeled data directly.
    model = SVC(kernel='linear', C=1) # Example model
    model.fit(X, y)

    joblib.dump(model, MODEL_FILE)
    print(f"Model trained successfully and saved to {MODEL_FILE}")
    return True

# --- API Endpoints ---

@app.route('/upload_image', methods=['POST'])
def upload_image():
    """
    Uploads an image to the system for labeling.
    Accepts: FormData with 'image' file.
    Returns: JSON with image_id and status.
    """
    if 'image' not in request.files:
        return jsonify({'error': 'No image file provided'}), 400

    file = request.files['image']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    if file:
        image_id = str(uuid.uuid4())
        filename = f"{image_id}_{file.filename}"
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(filepath)

        images_info[image_id] = {
            'filename': filename,
            'original_path': filepath,
            'aggregated_label': None,
            'status': 'pending' # pending, labeled, or rejected
        }
        raw_annotations[image_id] = [] # Initialize raw annotations for this image

        # Also add to labels_df to track its existence
        labels_df = load_labels_df()
        new_row = pd.DataFrame([{
            'image_id': image_id,
            'aggregated_label': None,
            'status': 'pending',
            'timestamp': pd.Timestamp.now().isoformat()
        }])
        labels_df = pd.concat([labels_df, new_row], ignore_index=True)
        save_labels_df(labels_df)

        return jsonify({'image_id': image_id, 'message': 'Image uploaded successfully for labeling'}), 201
    return jsonify({'error': 'Failed to upload image'}), 500

@app.route('/annotate_image', methods=['POST'])
def annotate_image():
    """
    Accepts an annotation for a specific image from an annotator.
    Accepts: JSON with 'image_id', 'annotator_id', 'label'.
    Returns: JSON with status and message.
    """
    data = request.get_json()
    image_id = data.get('image_id')
    annotator_id = data.get('annotator_id')
    label = data.get('label')

    if not all([image_id, annotator_id, label]):
        return jsonify({'error': 'Missing image_id, annotator_id, or label'}), 400

    if image_id not in images_info:
        return jsonify({'error': 'Image not found'}), 404

    # Store the raw annotation
    raw_annotations.setdefault(image_id, []).append({
        'annotator_id': annotator_id,
        'label': label,
        'timestamp': pd.Timestamp.now().isoformat()
    })

    # Attempt to aggregate labels after each new annotation
    aggregated_label = aggregate_labels(image_id)
    if aggregated_label:
        update_image_status(image_id, 'labeled', aggregated_label)
        return jsonify({
            'message': 'Annotation received. Labels aggregated.',
            'image_id': image_id,
            'aggregated_label': aggregated_label,
            'status': 'labeled'
        }), 200
    else:
        update_image_status(image_id, 'pending') # Ensure status is pending if not aggregated yet
        return jsonify({
            'message': 'Annotation received. Awaiting more annotations for aggregation.',
            'image_id': image_id,
            'status': 'pending'
        }), 200

@app.route('/get_image/<image_id>', methods=['GET'])
def get_image(image_id):
    """
    Retrieves an image file by its ID.
    Useful for annotators to fetch images.
    """
    if image_id not in images_info:
        return jsonify({'error': 'Image not found'}), 404

    filename = images_info[image_id]['filename']
    return send_from_directory(app.config['UPLOAD_FOLDER'], filename)

@app.route('/get_annotation_status/<image_id>', methods=['GET'])
def get_annotation_status(image_id):
    """
    Retrieves the current annotation status for a specific image.
    """
    if image_id not in images_info:
        return jsonify({'error': 'Image not found'}), 404

    image_data = images_info[image_id]
    current_annotations_count = len(raw_annotations.get(image_id, []))

    return jsonify({
        'image_id': image_id,
        'status': image_data['status'],
        'aggregated_label': image_data['aggregated_label'],
        'current_annotations_count': current_annotations_count,
        'min_annotators_required': MIN_ANNOTATORS_FOR_AGGREGATION,
        'raw_annotations': raw_annotations.get(image_id, [])
    })

@app.route('/get_all_labeled_data', methods=['GET'])
def get_all_labeled_data():
    """
    Retrieves all images that have been successfully labeled and aggregated.
    """
    labels_df = load_labels_df()
    labeled_data = labels_df[labels_df['status'] == 'labeled']

    result = []
    for _, row in labeled_data.iterrows():
        image_id = row['image_id']
        if image_id in images_info:
            result.append({
                'image_id': image_id,
                'aggregated_label': row['aggregated_label'],
                'image_url': f'/get_image/{image_id}'
            })
    return jsonify(result)

@app.route('/train_model', methods=['POST'])
def trigger_model_training():
    """
    Triggers the training of the machine learning model.
    """
    print("Initiating model training...")
    if train_model():
        return jsonify({'message': 'Model training initiated successfully.'}), 200
    else:
        return jsonify({'message': 'Model training failed or no sufficient data.'}), 500

@app.route('/predict', methods=['POST'])
def predict():
    """
    Makes a prediction using the trained model on a new image.
    Accepts: FormData with 'image' file.
    Returns: JSON with prediction.
    """
    if not os.path.exists(MODEL_FILE):
        return jsonify({'error': 'Model not trained yet. Please train the model first.'}), 404

    if 'image' not in request.files:
        return jsonify({'error': 'No image file provided'}), 400

    file = request.files['image']
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    if file:
        # Save the temporary image to process it
        temp_filepath = os.path.join(app.config['UPLOAD_FOLDER'], 'temp_predict_' + str(uuid.uuid4()) + '.png')
        file.save(temp_filepath)

        features = load_image_as_features(temp_filepath)
        os.remove(temp_filepath) # Clean up temporary file

        if features is None:
            return jsonify({'error': 'Could not extract features from image'}), 400

        try:
            model = joblib.load(MODEL_FILE)
            prediction = model.predict(features.reshape(1, -1))[0]
            return jsonify({'prediction': prediction}), 200
        except Exception as e:
            return jsonify({'error': f'Prediction failed: {str(e)}'}), 500
    return jsonify({'error': 'Failed to process image for prediction'}), 500


if __name__ == '__main__':
    # Initialize global state from disk on startup if files exist
    # (This is a simplified persistence. A real system would use a DB)
    _labels_df = load_labels_df()
    for _, row in _labels_df.iterrows():
        image_id = row['image_id']
        if image_id not in images_info: # Only add if not already from previous in-memory state
            # This part assumes original image files are still in UPLOAD_FOLDER
            # and their filenames are recoverable. This can be tricky.
            # A more robust system would store `filename` or `original_path` in labels.csv
            # For this example, we'll try to find it.
            found_filepath = None
            for fname in os.listdir(UPLOAD_FOLDER):
                if fname.startswith(f"{image_id}_"):
                    found_filepath = os.path.join(UPLOAD_FOLDER, fname)
                    break

            if found_filepath:
                images_info[image_id] = {
                    'filename': os.path.basename(found_filepath),
                    'original_path': found_filepath,
                    'aggregated_label': row['aggregated_label'] if pd.notna(row['aggregated_label']) else None,
                    'status': row['status']
                }
                # Reconstruct raw_annotations - THIS IS THE WEAKEST PART OF THIS IN-MEMORY PERSISTENCE.
                # Raw annotations are not persisted in this example, only aggregated labels.
                # In a real system, raw_annotations would be a table in a database.
                raw_annotations[image_id] = [] # Cleared on restart for simplicity.
                                                # Need a separate persistence mechanism for these.
            else:
                print(f"Warning: Image file for {image_id} not found in {UPLOAD_FOLDER} during startup load.")


    print("Starting Flask app...")
    print(f"Images info loaded: {len(images_info)} images")
    print(f"Labels loaded: {len(_labels_df)} entries")
    app.run(debug=True, host='0.0.0.0', port=5000)